-- FROM paper_embeddings e
-- JOIN papers p ON p.id = e.paper_id
-- ORDER BY distance
-- LIMIT 100; 


-- SELECT e.paper_id - count(DISTINCT embedding::text)
--            FROM paper_embeddings as e

-- SELECT  DISTINCT embedding::text
--            FROM paper_embeddings 
-- -- HAVING COUNT(*) > 1;
WITH Duplicated_papers(paper_id, title, n) 
AS (
  select p.id, p.title, paper_duplicates.duplicates, paper_duplicates.embedding
  from (SELECT ed.duplicates,ed.embedding, e.paper_id
  FROM (
    -- Embedding duplicates
    SELECT p.embedding, COUNT(*) AS duplicates
    FROM paper_embeddings as p
    GROUP BY p.embedding
    HAVING COUNT(*) > 1 
  )AS ed 
  LEFT JOIN paper_embeddings as e ON e.embedding = ed.embedding) as paper_duplicates
  JOIN papers as p ON p.id = paper_duplicates.paper_id
)

select p.id, dp.title, dp.n, dp.embedding from Duplicated_papers as dp
left join papers as p on p.id = dp.paper_id
group by dp.embedding, p.id, dp.title, dp.n




DELETE FROM papers p JOIN (
    SELECT title, MAX(id) AS MaxID
    FROM papers
    GROUP BY title
) as p2
ON p.title = p2.title 
AND p.id < p2.MaxID;


SELECT title, array_agg(arxiv_id ORDER BY id), array_agg(id ORDER BY id)
FROM papers
GROUP BY title, abstract
HAVING COUNT(*) > 1;
